const emp = items[0].json;

function getField(...keys) {
  for (const key of keys) {
    if (key === undefined || key === null) continue;
    if (Object.prototype.hasOwnProperty.call(emp, key) && emp[key] !== undefined && emp[key] !== null && emp[key] !== '') {
      return emp[key];
    }
  }
  return '';
}

function numberValue(value) {
  if (value === undefined || value === null || value === '') return 0;
  const parsed = parseFloat(String(value).replace(/,/g, '').trim());
  return Number.isFinite(parsed) ? parsed : 0;
}

function round2(num) {
  return Math.round((num + Number.EPSILON) * 100) / 100;
}

function formatMoney(num) {
  return round2(num).toFixed(2);
}

function numberToWords(num) {
  const ones = ['', 'ONE', 'TWO', 'THREE', 'FOUR', 'FIVE', 'SIX', 'SEVEN',
    'EIGHT', 'NINE', 'TEN', 'ELEVEN', 'TWELVE', 'THIRTEEN', 'FOURTEEN',
    'FIFTEEN', 'SIXTEEN', 'SEVENTEEN', 'EIGHTEEN', 'NINETEEN'];
  const tens = ['', '', 'TWENTY', 'THIRTY', 'FORTY', 'FIFTY',
    'SIXTY', 'SEVENTY', 'EIGHTY', 'NINETY'];

  function convert(n) {
    if (n === 0) return '';
    if (n < 20) return ones[n] + ' ';
    if (n < 100) return tens[Math.floor(n / 10)] + ' ' + ones[n % 10] + ' ';
    if (n < 1000) return ones[Math.floor(n / 100)] + ' HUNDRED ' + convert(n % 100);
    if (n < 100000) return convert(Math.floor(n / 1000)) + 'THOUSAND ' + convert(n % 1000);
    if (n < 10000000) return convert(Math.floor(n / 100000)) + 'LAKH ' + convert(n % 100000);
    return convert(Math.floor(n / 10000000)) + 'CRORE ' + convert(n % 10000000);
  }

  return convert(Math.abs(Math.round(num))).trim() + ' ONLY';
}

const basicSalary      = numberValue(getField('Basic Salary', 'basic_salary'));
const hra              = numberValue(getField('HRA', 'hra'));
const arrear           = numberValue(getField('Arrear', 'arrear'));
const pf               = numberValue(getField('PF', 'pf', 'EPF', 'epf'));
const esi              = numberValue(getField('ESI', 'esi'));
const advance          = numberValue(getField('Advance', 'advance'));
const voluntaryPf      = numberValue(getField('Voluntary PF', 'Voluntary pf', 'voluntary_pf'));
const professionalTax  = numberValue(getField('Professional Tax', 'professional_tax', 'PT', 'pt'));
const totalDeductions  = numberValue(getField('Total Deduction', 'total_deduction', 'deductions'));
const netSalary        = numberValue(getField('Net Salary', 'net_salary'));
const totalDays        = getField('TDays', 'total_days') || '';
const lwp              = getField('LWP', 'lwp') || '0';

const totalEarnings    = round2(basicSalary + hra + arrear);
const totalRate        = totalEarnings;

return [{
  json: {
    row_number:          getField('row_number'),
    branch:              getField('Branch', 'branch'),
    employee_id:         getField('employee_id', 'Emp Code', 'employee code'),
    employee_email:      getField('employee_email'),
    employee_name:       getField('employee_name', 'Employee Name'),
    father_spouse_name:  getField('father_spouse_name', 'Father/Spouse Name'),
    designation:         getField('Designation', 'designation'),
    department:          getField('Department', 'department'),
    doj:                 getField('DOJ', 'doj'),
    aadhar_no:           getField('Aadhar', 'AadharNo', 'aadhar_no'),
    pan_no:              getField('PAN', 'PANNo', 'pan_no'),
    uan:                 getField('UAN', 'uan'),
    esi_no:              getField('ESI No', 'ESINo', 'esi_no'),
    account_no:          getField('Account No', 'A/No.', 'account_no'),
    bank_name:           getField('Bank Name', 'B.Name', 'bank_name'),
    salary_month:        getField('salary_month'),
    generated_date:      getField('generated_date'),
    basic_salary:        formatMoney(basicSalary),
    hra:                 formatMoney(hra),
    arrear:              formatMoney(arrear),
    total_rate:          formatMoney(totalRate),
    total_earnings:      formatMoney(totalEarnings),
    pf:                  formatMoney(pf),
    esi:                 formatMoney(esi),
    advance:             formatMoney(advance),
    voluntary_pf:        formatMoney(voluntaryPf),
    professional_tax:    formatMoney(professionalTax),
    total_deductions:    formatMoney(totalDeductions),
    net_salary:          formatMoney(netSalary),
    net_salary_in_words: numberToWords(netSalary),
    pd:                  String(getField('PD', 'pd') || '0'),
    wo:                  String(getField('WO', 'wo') || '0'),
    holiday:             String(getField('Holiday', 'holiday') || '0'),
    cl:                  String(getField('CL', 'cl') || '0'),
    pl:                  String(getField('PL', 'pl') || '0'),
    co:                  String(getField('CO', 'co') || '0'),
    rl:                  String(getField('RL', 'rl') || '0'),
    wd:                  String(getField('WD', 'wd') || '0'),
    lwp:                 String(lwp),
    total_days:          String(totalDays || '')
  }
}];

const item = items[0];
const source = $('Prepare Payload').first().json;
const empId = source.employee_id || 'Payslip';
const month = String(source.salary_month || 'Month').replace(/[\/:*?"<>|]/g, '-');

if (item.binary && item.binary.pdf) {
  item.binary.pdf.fileName = `${empId}-${month}.pdf`;
  item.binary.pdf.mimeType = 'application/pdf';
}

return [item];

const data = items[0].json;

function escapeHtml(value) {
  return String(value ?? '')
    .replace(/&/g, '&amp;')
    .replace(/</g, '&lt;')
    .replace(/>/g, '&gt;')
    .replace(/"/g, '&quot;')
    .replace(/'/g, '&#39;');
}

function salaryRow(name, rate, earning) {
  return `<div class="salary-row">
    <span class="row-name">${escapeHtml(name)}</span>
    <span class="row-rate">${escapeHtml(rate)}</span>
    <span class="row-earn">${escapeHtml(earning)}</span>
    <span class="row-arr">0.00</span>
  </div>`;
}

function deductionRow(name, amount) {
  return `<div class="ded-row">
    <span class="ded-name">${escapeHtml(name)}</span>
    <span class="ded-amt">${escapeHtml(amount)}</span>
  </div>`;
}

const earningRows = [
  salaryRow('Basic', data.basic_salary, data.basic_salary),
  salaryRow('HRA', data.hra, data.hra),
  salaryRow('Arrear', data.arrear, data.arrear),
];

const deductionRows = [
  deductionRow('PF', data.pf),
  deductionRow('ESI', data.esi),
  deductionRow('Advance', data.advance),
  deductionRow('Voluntary PF', data.voluntary_pf),
  deductionRow('Professional Tax', data.professional_tax),
];

const replacements = {
  ...data,
  earning_rows: earningRows.join('\n'),
  deduction_rows: deductionRows.join('\n'),
};

const template = String.raw`<!DOCTYPE html>
