const rawHtmlKeys = new Set(['earning_rows', 'deduction_rows']);

const html = template.replace(/{{\s*([a-zA-Z0-9_]+)\s*}}/g, (_, key) => {
  const value = replacements[key] ?? '';
  return rawHtmlKeys.has(key) ? String(value) : escapeHtml(value);
});

return [{
  json: {
    ...data,
    html
  }
}];
